async (params, browser) => {
  // Open followers page
  await browser.open(`https://bsky.app/profile/${params.handle}/followers`)

  // Wait for followers list
  await browser.waitForSelector('div[role=\'link\'], a[href*=\'/profile/\'], [data-testid^=\'feedItem-by-\']', 15000)

  await browser.wait(2000)

  // Scroll for more
  await browser.scroll({ direction: 'down', amount: 1500 })

  await browser.wait(1500)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 1500 })

  await browser.wait(1500)

  // Extract followers
  const followers_data = await browser.evaluate(`const followers = []; const cards = document.querySelectorAll('div[role="link"][tabindex="0"], div[data-testid^="feedItem-by-"]'); for (let i = 0; i < Math.min(cards.length, 30); i++) { const el = cards[i]; const nameEl = el.querySelector('[data-testid="profileHeaderDisplayName"], span[style*="font-weight"], div[style*="font-weight"] span'); const linkEl = el.querySelector('a[href*="/profile/"]'); let handle = ''; if (linkEl) { const href = linkEl.getAttribute('href') || ''; const match = href.match(/\/profile\/([^/]+)/); if (match) handle = match[1]; } const bioEl = el.querySelector('[data-testid="profileHeaderDescription"], span[style*="color"]'); const avatarEl = el.querySelector('img[src*="avatar"]'); followers.push({ name: nameEl ? nameEl.textContent.trim() : '', handle: handle, bio: bioEl ? bioEl.textContent.trim().substring(0, 200) : '', avatar: avatarEl ? avatarEl.getAttribute('src') : '', url: linkEl ? linkEl.href : '' }); } return { handle: '' + params.handle + '', follower_count: followers.length, followers: followers, url: window.location.href }`)

  return followers_data
}
